  1	#!/usr/bin/env node
  2	/**
  3	 * 📡 RugMuncher Telegram-Ollama Bridge (Node.js)
  4	 * 
  5	 * Features:
  6	 * - Scheduled scans every 5 minutes for high-risk contracts
  7	 * - On-demand analysis via Telegram commands
  8	 * - Dual-channel alerts: Private (full) + Public (sanitized)
  9	 * - Admin-only commands for security
 10	 */
 11	
 12	const { Telegraf } = require('telegraf');
 13	const axios = require('axios');
 14	const cron = require('node-cron');
 15	
 16	// ═══════════════════════════════════════════════════════════
 17	// CONFIGURATION
 18	// ═══════════════════════════════════════════════════════════
 19	
 20	const BOT_TOKEN = process.env.TELEGRAM_BOT_TOKEN;
 21	const PRIVATE_CHANNEL = process.env.PRIVATE_CHANNEL || '-1001111111111'; // Admin bunker
 22	const PUBLIC_CHANNEL = process.env.PUBLIC_CHANNEL || '-1002222222222';   // Community alerts
 23	const ADMIN_IDS = (process.env.ADMIN_IDS || '').split(',').map(id => parseInt(id.trim())).filter(Boolean);
 24	
 25	const OLLAMA_URL = process.env.OLLAMA_URL || 'http://127.0.0.1:11434/api/generate';
 26	const DEFAULT_MODEL = process.env.DEFAULT_MODEL || 'gemma2:9b';
 27	
 28	const SCYLLA_HOSTS = (process.env.SCYLLA_HOSTS || '127.0.0.1').split(',');
 29	
 30	// ═══════════════════════════════════════════════════════════
 31	// UTILITIES
 32	// ═══════════════════════════════════════════════════════════
 33	
 34	/**
 35	 * Truncate wallet address for public display
 36	 */
 37	function truncateWallet(address, visible = 6) {
 38	  if (!address || address.length < visible * 2 + 4) return address;
 39	  return `${address.slice(0, visible)}...${address.slice(-visible)}`;
 40	}
 41	
 42	/**
 43	 * Get risk emoji based on score
 44	 */
 45	function getRiskEmoji(score) {
 46	  if (score >= 80) return '🚨';
 47	  if (score >= 60) return '⚠️';
 48	  if (score >= 40) return '⚡';
 49	  return '✅';
 50	}
 51	
 52	/**
 53	 * Check if user is admin
 54	 */
 55	function isAdmin(userId) {
 56	  return ADMIN_IDS.includes(userId);
 57	}
 58	
 59	// ═══════════════════════════════════════════════════════════
 60	// DUAL-CHANNEL ALERT FORMATTERS
 61	// ═══════════════════════════════════════════════════════════
 62	
 63	/**
 64	 * Format FULL alert for private admin channel
 65	 */
 66	function formatPrivateAlert(scan) {
 67	  const emoji = getRiskEmoji(scan.risk_score);
 68	  
 69	  let message = `
 70	${emoji} <b>RUGMUNCHBOT ALERT - ${scan.threat_level.toUpperCase()}</b>
 71	
 72	<b>Contract:</b> <code>${scan.contract_address}</code>
 73	<b>Chain:</b> ${scan.chain.toUpperCase()}
 74	<b>Risk Score:</b> <code>${scan.risk_score}/100</b>
 75	
 76	<b>🔍 FINDINGS:</b>`;
 77	
 78	  // Add findings with full details
 79	  for (const finding of (scan.findings || []).slice(0, 10)) {
 80	    const severityEmoji = {
 81	      'critical': '🔴',
 82	      'high': '🟠',
 83	      'medium': '🟡',
 84	      'low': '🔵'
 85	    }[finding.severity] || '⚪';
 86	    
 87	    message += `\n${severityEmoji} <b>${finding.title || 'Issue'}</b>`;
 88	    message += `\n   ${finding.description || 'No details'}`;
 89	    
 90	    if (finding.wallet) {
 91	      message += `\n   Wallet: <code>${finding.wallet}</code>`;
 92	    }
 93	    if (finding.tx_hash) {
 94	      message += `\n   TX: <code>${finding.tx_hash}</code>`;
 95	    }
 96	  }
 97	
 98	  // Include holder data if available
 99	  if (scan.holder_data && scan.holder_data.length > 0) {
100	    message += `\n\n<b>👥 TOP HOLDERS:</b>`;
101	    for (const holder of scan.holder_data.slice(0, 5)) {
102	      message += `\n  <code>${holder.address}</code>: ${holder.percentage}%`;
103	    }
104	  }
105	
106	  message += `\n\n<i>Full analysis via /analyze ${scan.contract_address}</i>`;
107	  
108	  return message;
109	}
110	
111	/**
112	 * Format SANITIZED alert for public channel
113	 */
114	function formatPublicAlert(scan) {
115	  const emoji = getRiskEmoji(scan.risk_score);
116	  const truncatedAddr = truncateWallet(scan.contract_address);
117	  
118	  let message = `
119	${emoji} <b>RUGMUNCHBOT ALERT</b>
120	
121	<b>Token:</b> <code>${truncatedAddr}</code>
122	<b>Chain:</b> ${scan.chain.toUpperCase()}
123	<b>Risk Score:</b> <code>${scan.risk_score}/100</b> - ${scan.threat_level.toUpperCase()}`;
124	
125	  // Sanitized findings summary
126	  if (scan.findings && scan.findings.length > 0) {
127	    const criticalCount = scan.findings.filter(f => f.severity === 'critical').length;
128	    const highCount = scan.findings.filter(f => f.severity === 'high').length;
129	    
130	    if (criticalCount > 0) {
131	      message += `\n⚠️ <b>${criticalCount} Critical</b> issues detected`;
132	    }
133	    if (highCount > 0) {
134	      message += `\n⚡ <b>${highCount} High Risk</b> issues detected`;
135	    }
136	  }
137	
138	  // Recommendation based on score
139	  if (scan.risk_score >= 80) {
140	    message += "\n\n🛑 <b>Recommendation:</b> Avoid - High probability of scam";
141	  } else if (scan.risk_score >= 60) {
142	    message += "\n\n⚠️ <b>Recommendation:</b> Exercise extreme caution";
143	  } else if (scan.risk_score >= 40) {
144	    message += "\n\n⚡ <b>Recommendation:</b> Research thoroughly before investing";
145	  } else {
146	    message += "\n\n✅ <b>Recommendation:</b> Lower risk detected, still DYOR";
147	  }
148	
149	  message += `\n\n<i>Detailed scan: @RugMuncherBot</i>`;
150	  
151	  return message;
152	}
153	
154	/**
155	 * Send dual-channel alert based on risk score
156	 */
157	async function sendDualChannelAlert(bot, scan) {
158	  const results = { private: false, public: false };
159	  
160	  if (scan.risk_score > 80) {
161	    // CRITICAL: Both channels
162	    console.log(`[ALERT] Critical risk ${scan.risk_score} - Sending to both channels`);
163	    
164	    try {
165	      await bot.telegram.sendMessage(
166	        PRIVATE_CHANNEL,
167	        formatPrivateAlert(scan),
168	        { parse_mode: 'HTML', disable_web_page_preview: true }
169	      );
170	      results.private = true;
171	    } catch (e) {
172	      console.error('Private channel error:', e.message);
173	    }
174	    
175	    try {
176	      await bot.telegram.sendMessage(
177	        PUBLIC_CHANNEL,
178	        formatPublicAlert(scan),
179	        { parse_mode: 'HTML', disable_web_page_preview: true }
180	      );
181	      results.public = true;
182	    } catch (e) {
183	      console.error('Public channel error:', e.message);
184	    }
185	    
186	  } else if (scan.risk_score > 60) {
187	    // HIGH: Private channel only
188	    console.log(`[ALERT] High risk ${scan.risk_score} - Sending to private channel`);
189	    
190	    try {
191	      await bot.telegram.sendMessage(
192	        PRIVATE_CHANNEL,
193	        formatPrivateAlert(scan),
194	        { parse_mode: 'HTML', disable_web_page_preview: true }
195	      );
196	      results.private = true;
197	    } catch (e) {
198	      console.error('Private channel error:', e.message);
199	    }
200	    
201	  } else {
202	    // MEDIUM/LOW: Log only
203	    console.log(`[LOG] Risk ${scan.risk_score} - Logged only`);
204	  }
205	  
206	  return results;
207	}
208	
209	// ═══════════════════════════════════════════════════════════
210	// OLLAMA INTEGRATION
211	// ═══════════════════════════════════════════════════════════
212	
213	/**
214	 * Call local Ollama for analysis
215	 */
216	async function callOllama(prompt, model = DEFAULT_MODEL) {
217	  try {
218	    const response = await axios.post(OLLAMA_URL, {
219	      model: model,
220	      prompt: prompt,
221	      stream: false,
222	      options: {
223	        temperature: 0.3,
224	        num_predict: 4096
225	      }
226	    }, {
227	      timeout: 120000 // 2 minutes
228	    });
229	    
230	    return response.data.response;
231	  } catch (e) {
232	    console.error('Ollama error:', e.message);
233	    throw e;
234	  }
235	}
236	
237	/**
238	 * Analyze contract via Ollama
239	 */
240	async function analyzeContract(contractAddress, chain = 'eth') {
241	  const prompt = `Analyze this ${chain} contract for honeypot and scam patterns: ${contractAddress}
242	
243	Provide analysis in JSON format with:
244	- risk_score (0-100)
245	- threat_level (safe/low/medium/high/critical)
246	- findings (array of issues)
247	- honeypot_detected (boolean)
248	- recommendation
249	
250	Be concise.`;
251	
252	  const response = await callOllama(prompt);
253	  
254	  // Try to parse JSON
255	  try {
256	    // Extract JSON from markdown if present
257	    let jsonStr = response;
258	    if (response.includes('```json')) {
259	      jsonStr = response.split('```json')[1].split('```')[0];
260	    } else if (response.includes('```')) {
261	      jsonStr = response.split('```')[1].split('```')[0];
262	    }
263	    
264	    return JSON.parse(jsonStr.trim());
265	  } catch (e) {
266	    // Return raw response if parsing fails
267	    return {
268	      risk_score: 50,
269	      threat_level: 'unknown',
270	      findings: [{ title: 'Analysis', description: response.slice(0, 500) }],
271	      parsing_error: true
272	    };
273	  }
274	}
