290	/**
291	 * Scheduled scan (runs every 5 minutes)
292	 */
293	async function scheduledScan(bot) {
294	  console.log(`[${new Date().toISOString()}] Running scheduled scan...`);
295	  
296	  try {
297	    const alerts = await checkRiskyContracts(70, 5);
298	    
299	    if (alerts.length === 0) {
300	      console.log('No high-risk contracts found');
301	      return;
302	    }
303	    
304	    console.log(`Found ${alerts.length} high-risk contracts`);
305	    
306	    for (const alert of alerts) {
307	      await sendDualChannelAlert(bot, alert);
308	    }
309	    
310	  } catch (e) {
311	    console.error('Scheduled scan error:', e.message);
312	  }
313	}
314	
315	// ═══════════════════════════════════════════════════════════
316	// TELEGRAM BOT SETUP
317	// ═══════════════════════════════════════════════════════════
318	
319	const bot = new Telegraf(BOT_TOKEN);
320	
321	// Start command
322	bot.command('start', (ctx) => {
323	  ctx.reply(`
324	🤖 RugMuncher Telegram Bridge
325	
326	Commands:
327	/analyze <contract> - Analyze contract (admin only)
328	/status - Check system status
329	/help - Show this message
330	
331	Auto-alerts every 5 minutes for high-risk contracts.
332	`);
333	});
334	
335	// Analyze command (admin only)
336	bot.command('analyze', async (ctx) => {
337	  const userId = ctx.from.id;
338	  
339	  if (!isAdmin(userId)) {
340	    return ctx.reply('⛔ Admin only.');
341	  }
342	  
343	  const args = ctx.message.text.split(' ').slice(1);
344	  if (args.length === 0) {
345	    return ctx.reply('Usage: /analyze <contract_address>');
346	  }
347	  
348	  const contract = args[0];
349	  
350	  // Validate address
351	  if (!contract.match(/^0x[a-fA-F0-9]{40}$/)) {
352	    return ctx.reply('❌ Invalid contract address format');
353	  }
354	  
355	  // Send analyzing message
356	  const msg = await ctx.reply(`🔍 Analyzing ${contract.slice(0, 10)}...`);
357	  
358	  try {
359	    const analysis = await analyzeContract(contract);
360	    
361	    // Create scan result
362	    const scan = {
363	      contract_address: contract,
364	      chain: 'eth',
365	      risk_score: analysis.risk_score || 50,
366	      threat_level: analysis.threat_level || 'unknown',
367	      findings: analysis.findings || []
368	    };
369	    
370	    // Send to both channels
371	    await sendDualChannelAlert(bot, scan);
372	    
373	    await ctx.telegram.editMessageText(
374	      ctx.chat.id,
375	      msg.message_id,
376	      null,
377	      `✅ Analysis complete. Risk score: ${scan.risk_score}/100`
378	    );
379	    
380	  } catch (e) {
381	    await ctx.telegram.editMessageText(
382	      ctx.chat.id,
383	      msg.message_id,
384	      null,
385	      `❌ Analysis failed: ${e.message}`
386	    );
387	  }
388	});
389	
390	// Status command (admin only)
391	bot.command('status', async (ctx) => {
392	  if (!isAdmin(ctx.from.id)) return;
393	  
394	  ctx.reply(`
395	📊 RugMuncher Bridge Status
396	
397	✅ Bot: Online
398	🔄 Scheduled scans: Every 5 minutes
399	📡 Ollama: ${OLLAMA_URL}
400	🤖 Model: ${DEFAULT_MODEL}
401	
402	Private channel: ${PRIVATE_CHANNEL}
403	Public channel: ${PUBLIC_CHANNEL}
404	`);
405	});
406	
407	// Help command
408	bot.command('help', (ctx) => {
409	  ctx.reply(`
410	🤖 RugMuncher Bridge Commands
411	
412	<b>Admin Commands:</b>
413	/analyze &lt;contract&gt; - Analyze a contract
414	/status - System status
415	
416	<b>Public:</b>
417	/help - Show this message
418	/start - Start message
419	
420	<b>Auto-Features:</b>
421	• Scans every 5 minutes for high-risk contracts
422	• Critical (>80): Alert to both channels
423	• High (60-80): Alert to private channel only
424	• Sanitizes wallet addresses for public
425	`);
426	});
427	
428	// ═══════════════════════════════════════════════════════════
429	// MAIN
430	// ═══════════════════════════════════════════════════════════
431	
432	async function main() {
433	  console.log('🚀 Starting RugMuncher Telegram Bridge...');
434	  console.log(`Private channel: ${PRIVATE_CHANNEL}`);
435	  console.log(`Public channel: ${PUBLIC_CHANNEL}`);
436	  console.log(`Ollama: ${OLLAMA_URL}`);
437	  
438	  // Schedule scans every 5 minutes
439	  cron.schedule('*/5 * * * *', () => {
440	    scheduledScan(bot);
441	  });
442	  
443	  console.log('⏰ Scheduled scans every 5 minutes');
444	  
445	  // Launch bot
446	  bot.launch();
447	  
448	  console.log('✅ Bridge is running');
449	  
450	  // Graceful shutdown
451	  process.once('SIGINT', () => bot.stop('SIGINT'));
452	  process.once('SIGTERM', () => bot.stop('SIGTERM'));
453	}
454	
455	// Run if called directly
456	if (require.main === module) {
457	  main().catch(console.error);
458	}
459	
460	module.exports = { bot, sendDualChannelAlert, analyzeContract };
